using UnityEngine;
using System;
using System.Collections.Generic;

// Player Stats Manager - Handles health, currency, and player state
public class PlayerStats : MonoBehaviour
{
    public static PlayerStats Instance { get; private set; }

    // Public variables for player stats (accessible from Inspector and other scripts)
    public float maxHealth = 100f;
    public float currentHealth = 100f;
    public int currency = 0;
    public int premiumCurrency = 0;
    public int playerLevel = 1;
    public float baseDefense = 5f;
    public float baseAttack = 10f;
    public float criticalChance = 0.05f;
    public float criticalMultiplier = 1.5f;
    public int totalKills = 0;
    public float playTime = 0f;

    // Equipment bonuses
    public float equipmentDefenseBonus = 0f;
    public float equipmentAttackBonus = 0f;
    public float equipmentHealthBonus = 0f;

    // Buff multipliers
    public float damageMultiplier = 1f;
    public float defenseMultiplier = 1f;
    public float currencyMultiplier = 1f;

    public event Action<float, float> OnHealthChanged;
    public event Action<int> OnCurrencyChanged;
    public event Action<int> OnPremiumCurrencyChanged;
    public event Action OnPlayerDied;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }

    private void Update()
    {
        playTime += Time.deltaTime;
    }

    public float GetEffectiveMaxHealth()
    {
        return maxHealth + equipmentHealthBonus;
    }

    public float GetEffectiveDefense()
    {
        return (baseDefense + equipmentDefenseBonus) * defenseMultiplier;
    }

    public float GetEffectiveAttack()
    {
        return (baseAttack + equipmentAttackBonus) * damageMultiplier;
    }

    public void TakeDamage(float rawDamage)
    {
        float calculatedDamage = DamageCalculator.CalculateIncomingDamage(rawDamage, GetEffectiveDefense(), playerLevel);
        currentHealth -= calculatedDamage;
        currentHealth = Mathf.Clamp(currentHealth, 0f, GetEffectiveMaxHealth());

        OnHealthChanged?.Invoke(currentHealth, GetEffectiveMaxHealth());

        if (currentHealth <= 0f)
        {
            Die();
        }
    }

    public float DealDamage(float enemyDefense, int enemyLevel)
    {
        float attack = GetEffectiveAttack();
        bool isCritical = UnityEngine.Random.value <= criticalChance;
        float damage = DamageCalculator.CalculateOutgoingDamage(attack, enemyDefense, playerLevel, enemyLevel, isCritical, criticalMultiplier);
        return damage;
    }

    public void Heal(float amount)
    {
        currentHealth += amount;
        currentHealth = Mathf.Clamp(currentHealth, 0f, GetEffectiveMaxHealth());
        OnHealthChanged?.Invoke(currentHealth, GetEffectiveMaxHealth());
    }

    public void FullHeal()
    {
        currentHealth = GetEffectiveMaxHealth();
        OnHealthChanged?.Invoke(currentHealth, GetEffectiveMaxHealth());
    }

    public void AddCurrency(int amount)
    {
        int adjustedAmount = Mathf.RoundToInt(amount * currencyMultiplier);
        currency += adjustedAmount;
        OnCurrencyChanged?.Invoke(currency);
    }

    public bool SpendCurrency(int amount)
    {
        if (currency >= amount)
        {
            currency -= amount;
            OnCurrencyChanged?.Invoke(currency);
            return true;
        }
        return false;
    }

    public void AddPremiumCurrency(int amount)
    {
        premiumCurrency += amount;
        OnPremiumCurrencyChanged?.Invoke(premiumCurrency);
    }

    public bool SpendPremiumCurrency(int amount)
    {
        if (premiumCurrency >= amount)
        {
            premiumCurrency -= amount;
            OnPremiumCurrencyChanged?.Invoke(premiumCurrency);
            return true;
        }
        return false;
    }

    public void LevelUp()
    {
        playerLevel++;
        maxHealth += 10f;
        baseAttack += 2f;
        baseDefense += 1f;
        FullHeal();
    }

    public void ApplyBuff(float damageMult, float defenseMult, float currencyMult, float duration)
    {
        StartCoroutine(BuffCoroutine(damageMult, defenseMult, currencyMult, duration));
    }

    private System.Collections.IEnumerator BuffCoroutine(float damageMult, float defenseMult, float currencyMult, float duration)
    {
        damageMultiplier *= damageMult;
        defenseMultiplier *= defenseMult;
        currencyMultiplier *= currencyMult;

        yield return new WaitForSeconds(duration);

        damageMultiplier /= damageMult;
        defenseMultiplier /= defenseMult;
        currencyMultiplier /= currencyMult;
    }

    private void Die()
    {
        OnPlayerDied?.Invoke();
        Debug.Log("Player has died!");
    }

    public void SaveStats()
    {
        PlayerPrefs.SetFloat("MaxHealth", maxHealth);
        PlayerPrefs.SetFloat("CurrentHealth", currentHealth);
        PlayerPrefs.SetInt("Currency", currency);
        PlayerPrefs.SetInt("PremiumCurrency", premiumCurrency);
        PlayerPrefs.SetInt("PlayerLevel", playerLevel);
        PlayerPrefs.SetFloat("BaseDefense", baseDefense);
        PlayerPrefs.SetFloat("BaseAttack", baseAttack);
        PlayerPrefs.SetFloat("CritChance", criticalChance);
        PlayerPrefs.SetFloat("CritMultiplier", criticalMultiplier);
        PlayerPrefs.SetInt("TotalKills", totalKills);
        PlayerPrefs.SetFloat("PlayTime", playTime);
        PlayerPrefs.Save();
    }

    public void LoadStats()
    {
        maxHealth = PlayerPrefs.GetFloat("MaxHealth", 100f);
        currentHealth = PlayerPrefs.GetFloat("CurrentHealth", 100f);
        currency = PlayerPrefs.GetInt("Currency", 0);
        premiumCurrency = PlayerPrefs.GetInt("PremiumCurrency", 0);
        playerLevel = PlayerPrefs.GetInt("PlayerLevel", 1);
        baseDefense = PlayerPrefs.GetFloat("BaseDefense", 5f);
        baseAttack = PlayerPrefs.GetFloat("BaseAttack", 10f);
        criticalChance = PlayerPrefs.GetFloat("CritChance", 0.05f);
        criticalMultiplier = PlayerPrefs.GetFloat("CritMultiplier", 1.5f);
        totalKills = PlayerPrefs.GetInt("TotalKills", 0);
        playTime = PlayerPrefs.GetFloat("PlayTime", 0f);
    }
}

// Damage Calculator - Client-side damage calculations
public static class DamageCalculator
{
    public static float CalculateIncomingDamage(float rawDamage, float defense, int playerLevel)
    {
        // Damage reduction formula: damage = raw * (100 / (100 + defense))
        float damageReduction = 100f / (100f + defense);
        float finalDamage = rawDamage * damageReduction;

        // Minimum damage is always 1
        finalDamage = Mathf.Max(finalDamage, 1f);

        return finalDamage;
    }

    public static float CalculateOutgoingDamage(float attack, float enemyDefense, int playerLevel, int enemyLevel, bool isCritical, float critMultiplier)
    {
        // Level scaling factor
        float levelDifference = playerLevel - enemyLevel;
        float levelScaling = 1f + (levelDifference * 0.05f);
        levelScaling = Mathf.Clamp(levelScaling, 0.5f, 2.0f);

        // Base damage calculation
        float baseDamage = attack * levelScaling;

        // Apply enemy defense
        float damageAfterDefense = baseDamage * (100f / (100f + enemyDefense));

        // Apply critical hit
        if (isCritical)
        {
            damageAfterDefense *= critMultiplier;
        }

        // Add small random variance (+/- 10%)
        float variance = UnityEngine.Random.Range(0.9f, 1.1f);
        damageAfterDefense *= variance;

        return Mathf.Max(damageAfterDefense, 1f);
    }

    public static float CalculateElementalDamage(float baseDamage, ElementType attackElement, ElementType defenseElement)
    {
        float multiplier = GetElementalMultiplier(attackElement, defenseElement);
        return baseDamage * multiplier;
    }

    private static float GetElementalMultiplier(ElementType attack, ElementType defense)
    {
        if (attack == ElementType.Fire && defense == ElementType.Nature) return 1.5f;
        if (attack == ElementType.Nature && defense == ElementType.Water) return 1.5f;
        if (attack == ElementType.Water && defense == ElementType.Fire) return 1.5f;
        if (attack == ElementType.Fire && defense == ElementType.Water) return 0.5f;
        if (attack == ElementType.Water && defense == ElementType.Nature) return 0.5f;
        if (attack == ElementType.Nature && defense == ElementType.Fire) return 0.5f;
        if (attack == ElementType.Light && defense == ElementType.Dark) return 1.75f;
        if (attack == ElementType.Dark && defense == ElementType.Light) return 1.75f;
        return 1.0f;
    }
}

public enum ElementType
{
    None,
    Fire,
    Water,
    Nature,
    Light,
    Dark
}

