// Price Calculator - Client-side price calculations
public static class PriceCalculator
{
    // Dynamic pricing based on player level and item properties
    public static int CalculatePrice(ShopItem item, int playerLevel)
    {
        float basePrice = item.baseCurrencyPrice;

        // Scale price with player level (items get more expensive as player levels up)
        float levelMultiplier = 1f + (playerLevel - 1) * 0.1f;
        float scaledPrice = basePrice * levelMultiplier;

        return Mathf.RoundToInt(scaledPrice);
    }

    public static int CalculateSellPrice(ShopItem item, int playerLevel)
    {
        int buyPrice = CalculatePrice(item, playerLevel);
        // Sell price is 40% of buy price
        return Mathf.RoundToInt(buyPrice * 0.4f);
    }

    public static int CalculateBulkDiscount(int pricePerItem, int quantity)
    {
        float discount = 1f;
        if (quantity >= 10) discount = 0.8f;
        else if (quantity >= 5) discount = 0.9f;
        else if (quantity >= 3) discount = 0.95f;

        return Mathf.RoundToInt(pricePerItem * quantity * discount);
    }

    public static int CalculateUpgradePrice(int basePrice, int currentUpgradeLevel)
    {
        // Each upgrade level costs 50% more than the previous
        float multiplier = Mathf.Pow(1.5f, currentUpgradeLevel);
        return Mathf.RoundToInt(basePrice * multiplier);
    }
}

