    public void GenerateDailyDeals()
    {
        dailyDeals.Clear();
        // Pick 3 random items with a 20% discount for daily deals
        List<ShopItem> shuffled = new List<ShopItem>(availableItems);
        for (int i = shuffled.Count - 1; i > 0; i--)
        {
            int j = UnityEngine.Random.Range(0, i + 1);
            ShopItem temp = shuffled[i];
            shuffled[i] = shuffled[j];
            shuffled[j] = temp;
        }

        int dealCount = Mathf.Min(3, shuffled.Count);
        for (int i = 0; i < dealCount; i++)
        {
            ShopItem deal = new ShopItem
            {
                itemId = shuffled[i].itemId + "_deal",
                itemName = shuffled[i].itemName + " (DEAL!)",
                description = shuffled[i].description,
                icon = shuffled[i].icon,
                baseCurrencyPrice = Mathf.RoundToInt(shuffled[i].baseCurrencyPrice * 0.8f),
                premiumCurrencyPrice = Mathf.RoundToInt(shuffled[i].premiumCurrencyPrice * 0.8f),
                itemType = shuffled[i].itemType,
                priceType = shuffled[i].priceType,
                isConsumable = shuffled[i].isConsumable,
                maxStack = shuffled[i].maxStack,
                currentStock = 1,
                healthBonus = shuffled[i].healthBonus,
                attackBonus = shuffled[i].attackBonus,
                defenseBonus = shuffled[i].defenseBonus,
                critChanceBonus = shuffled[i].critChanceBonus,
                healAmount = shuffled[i].healAmount,
                buffDamageMultiplier = shuffled[i].buffDamageMultiplier,
                buffDefenseMultiplier = shuffled[i].buffDefenseMultiplier,
                buffCurrencyMultiplier = shuffled[i].buffCurrencyMultiplier,
                buffDuration = shuffled[i].buffDuration
            };
            dailyDeals.Add(deal);
        }
    }

    public bool PurchaseItem(ShopItem item, int quantity = 1)
    {
        if (item == null)
        {
            OnPurchaseFailed?.Invoke("Item not found.");
            return false;
        }

        // Check stock
        if (item.currentStock != -1 && item.currentStock < quantity)
        {
            OnPurchaseFailed?.Invoke("Not enough stock available.");
            return false;
        }

        // Handle IAP items separately
        if (item.isIAP)
        {
            InitiateIAPPurchase(item);
            return false; // Will be resolved async
        }

        // Calculate total price
        int totalPrice;
        if (item.priceType == CurrencyType.Premium)
        {
            totalPrice = item.premiumCurrencyPrice * quantity;
            if (quantity > 1)
            {
                totalPrice = PriceCalculator.CalculateBulkDiscount(item.premiumCurrencyPrice, quantity);
            }

            if (!playerStats.SpendPremiumCurrency(totalPrice))
            {
                OnPurchaseFailed?.Invoke("Not enough premium currency.");
                return false;
            }
        }
        else
        {
            int pricePerItem = PriceCalculator.CalculatePrice(item, playerStats.playerLevel);
            totalPrice = pricePerItem * quantity;
            if (quantity > 1)
            {
                totalPrice = PriceCalculator.CalculateBulkDiscount(pricePerItem, quantity);
            }

            if (!playerStats.SpendCurrency(totalPrice))
            {
                OnPurchaseFailed?.Invoke("Not enough currency.");
                return false;
            }
        }

        // Apply item effects
        for (int i = 0; i < quantity; i++)
        {
            ApplyItemEffects(item);
        }

        // Update stock
        if (item.currentStock != -1)
        {
            item.currentStock -= quantity;
        }

        // Add to inventory if applicable
        if (inventory != null)
        {
            inventory.AddItem(item, quantity);
        }

        OnItemPurchased?.Invoke(item);
        Debug.Log($"Purchased {quantity}x {item.itemName} for {totalPrice} {item.priceType}");
        return true;
    }

    public bool SellItem(ShopItem item, int quantity = 1)
    {
        if (item == null || item.isIAP) return false;

        if (inventory != null && !inventory.RemoveItem(item.itemId, quantity))
        {
            OnPurchaseFailed?.Invoke("You don't have enough of this item to sell.");
            return false;
        }

        int sellPrice = PriceCalculator.CalculateSellPrice(item, playerStats.playerLevel) * quantity;

        if (item.priceType == CurrencyType.Premium)
        {
            playerStats.AddPremiumCurrency(sellPrice);
        }
        else
        {
            playerStats.AddCurrency(sellPrice);
        }

        // Remove equipment bonuses if it was equipped
        RemoveItemEffects(item, quantity);

        Debug.Log($"Sold {quantity}x {item.itemName} for {sellPrice}");
        return true;
    }

    private void ApplyItemEffects(ShopItem item)
    {
        switch (item.itemType)
        {
            case ShopItemType.Consumable:
                if (item.healAmount > 0)
                {
                    playerStats.Heal(item.healAmount);
                }
                break;

            case ShopItemType.Weapon:
                playerStats.equipmentAttackBonus += item.attackBonus;
                playerStats.criticalChance += item.critChanceBonus;
                break;

            case ShopItemType.Armor:
                playerStats.equipmentDefenseBonus += item.defenseBonus;
                playerStats.equipmentHealthBonus += item.healthBonus;
                break;

            case ShopItemType.Accessory:
                playerStats.equipmentAttackBonus += item.attackBonus;
                playerStats.equipmentDefenseBonus += item.defenseBonus;
                playerStats.equipmentHealthBonus += item.healthBonus;
                playerStats.criticalChance += item.critChanceBonus;
                break;

            case ShopItemType.Buff:
                playerStats.ApplyBuff(
                    item.buffDamageMultiplier,
                    item.buffDefenseMultiplier,
                    item.buffCurrencyMultiplier,
                    item.buffDuration
                );
                break;

            case ShopItemType.CurrencyPack:
                playerStats.AddPremiumCurrency(item.premiumCurrencyPrice);
                break;
        }
    }

    private void RemoveItemEffects(ShopItem item, int quantity)
    {
        for (int i = 0; i < quantity; i++)
        {
            switch (item.itemType)
            {
                case ShopItemType.Weapon:
                    playerStats.equipmentAttackBonus -= item.attackBonus;
                    playerStats.criticalChance -= item.critChanceBonus;
                    break;

                case ShopItemType.Armor:
                    playerStats.equipmentDefenseBonus -= item.defenseBonus;
                    playerStats.equipmentHealthBonus -= item.healthBonus;
                    break;

                case ShopItemType.Accessory:
                    playerStats.equipmentAttackBonus -= item.attackBonus;
                    playerStats.equipmentDefenseBonus -= item.defenseBonus;
                    playerStats.equipmentHealthBonus -= item.healthBonus;
                    playerStats.criticalChance -= item.critChanceBonus;
                    break;
            }
        }
    }

    private void InitiateIAPPurchase(ShopItem item)
    {
        Debug.Log($"Initiating IAP purchase for product: {item.iapProductId}");
        // Integration point for Unity IAP
        // In production, use UnityEngine.Purchasing.IStoreController
        IAPManager.Instance?.PurchaseProduct(item.iapProductId, (success) =>
        {
            if (success)
            {
                ApplyItemEffects(item);
                OnItemPurchased?.Invoke(item);
                Debug.Log($"IAP Purchase successful: {item.itemName}");
            }
            else
            {
                OnPurchaseFailed?.Invoke("IAP Purchase failed or cancelled.");
            }
        });
    }

    public ShopItem GetItemById(string itemId)
    {
        return availableItems.Find(i => i.itemId == itemId);
    }

    public List<ShopItem> GetItemsByType(ShopItemType type)
    {
        return availableItems.FindAll(i => i.itemType == type);
    }

    public int GetItemPrice(ShopItem item)
    {
        if (item.priceType == CurrencyType.Premium)
            return item.premiumCurrencyPrice;
        return PriceCalculator.CalculatePrice(item, playerStats.playerLevel);
    }
}

// Inventory Manager
public class InventoryManager : MonoBehaviour
{
    public static InventoryManager Instance { get; private set; }

    [System.Serializable]
    public class InventorySlot
    {
        public ShopItem item;
        public int quantity;
    }

    public List<InventorySlot> inventorySlots = new List<InventorySlot>();
    public int maxInventorySize = 50;

    public event Action OnInventoryChanged;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }

    public bool AddItem(ShopItem item, int quantity = 1)
    {
        // Check if item already exists and is stackable
        InventorySlot existingSlot = inventorySlots.Find(s => s.item.itemId == item.itemId);

        if (existingSlot != null && item.isConsumable)
        {
            int newQuantity = existingSlot.quantity + quantity;
            if (newQuantity <= item.maxStack)
            {
                existingSlot.quantity = newQuantity;
                OnInventoryChanged?.Invoke();
                return true;
            }
            else
            {
                Debug.Log("Stack is full.");
                return false;
            }
        }

        if (inventorySlots.Count >= maxInventorySize)
        {
            Debug.Log("Inventory is full.");
            return false;
        }

        inventorySlots.Add(new InventorySlot { item = item, quantity = quantity });
        OnInventoryChanged?.Invoke();
        return true;
    }

    public bool RemoveItem(string itemId, int quantity = 1)
    {
        InventorySlot slot = inventorySlots.Find(s => s.item.itemId == itemId);

        if (slot == null || slot.quantity < quantity)
            return false;

        slot.quantity -= quantity;
        if (slot.quantity <= 0)
        {
            inventorySlots.Remove(slot);
        }

        OnInventoryChanged?.Invoke();
        return true;
    }

    public bool HasItem(string itemId, int quantity = 1)
    {
        InventorySlot slot = inventorySlots.Find(s => s.item.itemId == itemId);
        return slot != null && slot.quantity >= quantity;
    }

    public int GetItemCount(string itemId)
    {
        InventorySlot slot = inventorySlots.Find(s => s.item.itemId == itemId);
        return slot?.quantity ?? 0;
    }
}

// IAP Manager - Handles In-App Purchases
public class IAPManager : MonoBehaviour
{
    public static IAPManager Instance { get; private set; }

    [System.Serializable]
    public class IAPProduct
    {
        public string productId;
        public string displayName;
        public string priceString;
        public float priceValue;
        public int premiumCurrencyReward;
        public int bonusCurrency;
    }

    public List<IAPProduct> products = new List<IAPProduct>();

    private Action<bool> currentPurchaseCallback;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
            InitializeIAP();
        }
        else
        {
            Destroy(gameObject);
        }
    }

    private void InitializeIAP()
    {
        // Define IAP products
        products.Add(new IAPProduct
        {
            productId = "com.game.gems100",
            displayName = "100 Gems",
            priceString = "$0.99",
            priceValue = 0.99f,
            premiumCurrencyReward = 100,
            bonusCurrency = 0
        });

        products.Add(new IAPProduct
        {
            productId = "com.game.gems500",
            displayName = "500 Gems + 100 Bonus",
            priceString = "$4.99",
            priceValue = 4.99f,
            premiumCurrencyReward = 500,
            bonusCurrency = 100
        });

        products.Add(new IAPProduct
        {
            productId = "com.game.gems1200",
            displayName = "1200 Gems + 300 Bonus",
            priceString = "$9.99",
            priceValue = 9.99f,
            premiumCurrencyReward = 1200,
            bonusCurrency = 300
        });

        products.Add(new IAPProduct
        {
            productId = "com.game.starterpack",
            displayName = "Starter Pack",
            priceString = "$2.99",
            priceValue = 2.99f,
            premiumCurrencyReward = 200,
            bonusCurrency = 50
        });

        // In production, initialize Unity IAP here:
        // var builder = ConfigurationBuilder.Instance(StandardPurchasingModule.Instance());
        // foreach (var product in products)
        //     builder.AddProduct(product.productId, ProductType.Consumable);
        // UnityPurchasing.Initialize(this, builder);

        Debug.Log("IAP Manager initialized with " + products.Count + " products.");
    }

    public void PurchaseProduct(string productId, Action<bool> callback)
    {
        currentPurchaseCallback = callback;

        IAPProduct product = products.Find(p => p.productId == productId);
        if (product == null)
        {
            Debug.LogError($"IAP Product not found: {productId}");
            callback?.Invoke(false);
            return;
        }

        Debug.Log($"Processing IAP purchase: {product.displayName} ({product.priceString})");

        // In production, call:
        // storeController.InitiatePurchase(productId);

        // Simulate successful purchase for development
        OnPurchaseComplete(product);
    }

    private void OnPurchaseComplete(IAPProduct product)
    {
        int totalReward = product.premiumCurrencyReward + product.bonusCurrency;
        PlayerStats.Instance.AddPremiumCurrency(totalReward);

        Debug.Log($"IAP Purchase complete: {product.displayName}, awarded {totalReward} premium currency");

        currentPurchaseCallback?.Invoke(true);
        currentPurchaseCallback = null;
    }

    public void RestorePurchases()
    {
        Debug.Log("Restoring purchases...");
        // In production:
        // extensionProvider.GetExtension<IAppleExtensions>().RestoreTransactions((result) => { });
    }
}

// Enemy class for combat demonstration
public class Enemy : MonoBehaviour
{
    public string enemyName = "Goblin";
    public float maxHealth = 50f;
    public float currentHealth = 50f;
    public float attack = 8f;
    public float defense = 3f;
    public int level = 1;
    public int currencyReward = 25;
    public int experienceReward = 10;
    public ElementType elementType = ElementType.None;

    public event Action<float, float> OnEnemyHealthChanged;
    public event Action<Enemy> OnEnemyDied;

    public void TakeDamage(float rawDamage, ElementType attackElement = ElementType.None)
    {
        float damage = DamageCalculator.CalculateIncomingDamage(rawDamage, defense, level);

        // Apply elemental modifier
        if (attackElement != ElementType.None)
        {
            damage = DamageCalculator.CalculateElementalDamage(damage, attackElement, elementType);
        }

        currentHealth -= damage;
        currentHealth = Mathf.Max(currentHealth, 0f);

        OnEnemyHealthChanged?.Invoke(currentHealth, maxHealth);

        Debug.Log($"{enemyName} took {damage:F1} damage. HP: {currentHealth:F1}/{maxHealth}");

        if (currentHealth <= 0f)
        {
            Die();
        }
    }

    public void AttackPlayer()
    {
        PlayerStats player = PlayerStats.Instance;
        if (player != null)
        {
            player.TakeDamage(attack);
            Debug.Log($"{enemyName} attacks player for {attack} raw damage.");
        }
    }

    private void Die()
    {
        PlayerStats player = PlayerStats.Instance;
        if (player != null)
        {
            player.AddCurrency(currencyReward);
            player.totalKills++;
        }

        OnEnemyDied?.Invoke(this);
        Debug.Log($"{enemyName} defeated! Rewarded {currencyReward} currency.");
        Destroy(gameObject);
    }
}

// Game Manager - Ties everything together
public class GameManager : MonoBehaviour
{
    public static GameManager Instance { get; private set; }

    public bool isGamePaused = false;

    private void Awake()
    {
        if (Instance == null)
        {
            Instance = this;
            DontDestroyOnLoad(gameObject);
        }
        else
        {
            Destroy(gameObject);
        }
    }

    private void Start()
    {
        // Load saved data
        if (PlayerStats.Instance != null)
        {
            PlayerStats.Instance.LoadStats();
            PlayerStats.Instance.OnPlayerDied += HandlePlayerDeath;
            PlayerStats.Instance.OnCurrencyChanged += (c) => Debug.Log($"Currency: {c}");
        }
    }

    private void HandlePlayerDeath()
    {
        Debug.Log("Game Over - Player has died!");
        // Offer revive for premium currency
        OfferRevive();
    }

    private void OfferRevive()
    {
        int reviveCost = 50; // premium currency
        if (PlayerStats.Instance.premiumCurrency >= reviveCost)
        {
            Debug.Log($"Revive available for {reviveCost} gems.");
            // In production, show UI prompt
            // RevivePlayer(reviveCost);
        }
        else
        {
            Debug.Log("Not enough gems to revive. Showing ad offer...");
            // Offer ad-based revive
        }
    }

    public void RevivePlayer(int premiumCost)
    {
        if (PlayerStats.Instance.SpendPremiumCurrency(premiumCost))
        {
            PlayerStats.Instance.FullHeal();
            Debug.Log("Player revived!");
        }
    }

    public void PauseGame()
    {
        isGamePaused = true;
        Time.timeScale = 0f;
    }

    public void ResumeGame()
    {
        isGamePaused = false;
        Time.timeScale = 1f;
    }

    public void SaveGame()
    {
        PlayerStats.Instance?.SaveStats();
        Debug.Log("Game saved.");
    }

    private void OnApplicationPause(bool pauseStatus)
    {
        if (pauseStatus)
        {
            SaveGame();
        }
    }

    private void OnApplicationQuit()
    {
        SaveGame();
    }
}